// ── Palette ───────────────────────────────────────────────────────────────────
const KOI = [
  { body: '#d94f3d', fin: '#f4a69e', spot: '#fff3' },
  { body: '#e8a838', fin: '#c97d20', spot: '#fff4' },
  { body: '#f0ede6', fin: '#c5bfb4', spot: '#d94f3d88' },
  { body: '#f0c040', fin: '#d4953a', spot: '#0002' },
  { body: '#1a1a1a', fin: '#444', spot: '#fff3' },
  { body: '#e05c2b', fin: '#f0a87a', spot: '#fff3' },
];

// ── Fish ──────────────────────────────────────────────────────────────────────
class Fish {
  constructor(W, H) {
    this.x = 80 + Math.random() * (W - 160);
    this.y = 80 + Math.random() * (H - 160);
    const a = Math.random() * Math.PI * 2;
    this.spd = 0.7 + Math.random() * 1.1;
    this.vx = Math.cos(a) * this.spd;
    this.vy = Math.sin(a) * this.spd;
    this.angle = a;
    this.len = 36 + Math.random() * 28;
    this.pal = KOI[Math.floor(Math.random() * KOI.length)];
    this.wig = Math.random() * Math.PI * 2;
    this.wigSpd = 0.07 + Math.random() * 0.05;
    this.wander = Math.random() * Math.PI * 2;
    this.svgIndex = Math.floor(Math.random() * 6);
    this.scale = 0.7 + Math.random() * 0.35;
  }

  update(W, H, cur) {
    this.wig += this.wigSpd;
    this.wander += (Math.random() - 0.5) * 0.12;

    let fx = Math.cos(this.wander) * 0.018;
    let fy = Math.sin(this.wander) * 0.018;

    const dx = this.x - cur.x, dy = this.y - cur.y;
    const d = Math.sqrt(dx * dx + dy * dy);
    if (d < 160 && d > 0) {
      const f = Math.pow((160 - d) / 160, 2) * 0.9;
      fx += (dx / d) * f; fy += (dy / d) * f;
    }

    const m = 70;
    if (this.x < m) fx += (m - this.x) / m * 0.06;
    if (this.x > W - m) fx -= (this.x - W + m) / m * 0.06;
    if (this.y < m) fy += (m - this.y) / m * 0.06;
    if (this.y > H - m) fy -= (this.y - H + m) / m * 0.06;

    this.vx += fx; this.vy += fy;
    const spd = Math.sqrt(this.vx * this.vx + this.vy * this.vy);
    const maxS = this.spd * (d < 140 ? 3.2 : 1);
    const minS = 0.35;
    if (spd > maxS) { this.vx = this.vx / spd * maxS; this.vy = this.vy / spd * maxS; }
    if (spd < minS) { this.vx = this.vx / spd * minS; this.vy = this.vy / spd * minS; }

    const ta = Math.atan2(this.vy, this.vx);
    let diff = ta - this.angle;
    while (diff > Math.PI) diff -= Math.PI * 2;
    while (diff < -Math.PI) diff += Math.PI * 2;
    this.angle += diff * 0.06;

    this.x += this.vx; this.y += this.vy;
    if (this.x < -70) this.x = W + 70; if (this.x > W + 70) this.x = -70;
    if (this.y < -70) this.y = H + 70; if (this.y > H + 70) this.y = -70;
  }

  draw(ctx, svgImgs) {
    // SVG fish mode
    if (svgImgs && svgImgs[this.svgIndex]) {
      const img = svgImgs[this.svgIndex];
      const w = 100 * this.scale, h = 42 * this.scale;
      const tw = Math.sin(this.wig) * 0.06;
      ctx.save();
      ctx.translate(this.x, this.y);
      ctx.rotate(this.angle + tw);
      ctx.globalAlpha = 0.15;
      ctx.filter = 'blur(3px)';
      ctx.drawImage(img, -w/2+3, -h/2+5, w, h);
      ctx.filter = 'none';
      ctx.globalAlpha = 1;
      ctx.drawImage(img, -w/2, -h/2, w, h);
      ctx.restore();
      return;
    }
    const { body, fin, spot } = this.pal;
    const L = this.len;
    const tw = Math.sin(this.wig) * 0.38;

    ctx.save();
    ctx.translate(this.x, this.y);
    ctx.rotate(this.angle);

    ctx.save();
    ctx.translate(4, 5);
    ctx.globalAlpha = 0.12;
    ctx.beginPath();
    ctx.ellipse(0, 0, L * 0.44, L * 0.16, 0, 0, Math.PI * 2);
    ctx.fillStyle = '#000';
    ctx.fill();
    ctx.restore();

    ctx.save();
    ctx.translate(-L * 0.38, 0);
    ctx.rotate(tw);
    ctx.globalAlpha = 0.82;
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.bezierCurveTo(-L * 0.28, -L * 0.22, -L * 0.42, -L * 0.28, -L * 0.38, 0);
    ctx.bezierCurveTo(-L * 0.42, L * 0.28, -L * 0.28, L * 0.22, 0, 0);
    ctx.fillStyle = fin;
    ctx.fill();
    ctx.restore();

    [-1, 1].forEach(s => {
      ctx.save();
      ctx.translate(L * 0.08, 0);
      ctx.rotate(s * (0.65 + Math.sin(this.wig * 0.5) * 0.18));
      ctx.globalAlpha = 0.65;
      ctx.beginPath();
      ctx.ellipse(0, s * L * 0.09, L * 0.22, L * 0.07, 0, 0, Math.PI * 2);
      ctx.fillStyle = fin;
      ctx.fill();
      ctx.restore();
    });

    ctx.globalAlpha = 1;
    ctx.beginPath();
    ctx.ellipse(0, 0, L * 0.44, L * 0.16, 0, 0, Math.PI * 2);
    ctx.fillStyle = body;
    ctx.fill();

    const sg = ctx.createRadialGradient(-L * 0.1, -L * 0.07, 0, 0, 0, L * 0.42);
    sg.addColorStop(0, 'rgba(255,255,255,0.38)');
    sg.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.beginPath();
    ctx.ellipse(0, 0, L * 0.44, L * 0.16, 0, 0, Math.PI * 2);
    ctx.fillStyle = sg;
    ctx.fill();

    ctx.globalAlpha = 0.55;
    ctx.fillStyle = spot;
    ctx.beginPath();
    ctx.ellipse(L * 0.06, L * 0.04, L * 0.11, L * 0.08, 0.4, 0, Math.PI * 2);
    ctx.fill();

    ctx.globalAlpha = 0.78;
    ctx.beginPath();
    ctx.moveTo(L * 0.22, -L * 0.16);
    ctx.bezierCurveTo(L * 0.08, -L * 0.32, -L * 0.08, -L * 0.3, -L * 0.18, -L * 0.16);
    ctx.fillStyle = fin;
    ctx.fill();

    ctx.globalAlpha = 1;
    ctx.beginPath();
    ctx.arc(L * 0.35, -L * 0.04, 3.8, 0, Math.PI * 2);
    ctx.fillStyle = '#180800';
    ctx.fill();
    ctx.beginPath();
    ctx.arc(L * 0.34, -L * 0.05, 1.4, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255,255,255,0.75)';
    ctx.fill();

    ctx.restore();
  }
}

// ── Ripple ────────────────────────────────────────────────────────────────────
class Ripple {
  constructor(x, y) {
    this.x = x; this.y = y;
    this.rings = [{ r: 3, alpha: 0.65, spd: 1.6 }, { r: 1, alpha: 0.4, spd: 1.2 }];
  }
  update() { this.rings.forEach(r => { r.r += r.spd; r.alpha -= 0.013; }); }
  draw(ctx, svgImgs) {
    // SVG fish mode
    if (svgImgs && svgImgs[this.svgIndex]) {
      const img = svgImgs[this.svgIndex];
      const w = 100 * this.scale, h = 42 * this.scale;
      const tw = Math.sin(this.wig) * 0.06;
      ctx.save();
      ctx.translate(this.x, this.y);
      ctx.rotate(this.angle + tw);
      ctx.globalAlpha = 0.15;
      ctx.filter = 'blur(3px)';
      ctx.drawImage(img, -w/2+3, -h/2+5, w, h);
      ctx.filter = 'none';
      ctx.globalAlpha = 1;
      ctx.drawImage(img, -w/2, -h/2, w, h);
      ctx.restore();
      return;
    }
    this.rings.forEach(r => {
      if (r.alpha <= 0) return;
      ctx.beginPath();
      ctx.arc(this.x, this.y, r.r, 0, Math.PI * 2);
      ctx.strokeStyle = `rgba(255,255,255,${r.alpha})`;
      ctx.lineWidth = 1.5;
      ctx.stroke();
    });
  }
  isDead() { return this.rings[0].alpha <= 0; }
}

// ── Lily pad ──────────────────────────────────────────────────────────────────
function drawPad(ctx, x, y, r, rot) {
  ctx.save();
  ctx.translate(x, y);
  ctx.rotate(rot);
  ctx.globalAlpha = 0.82;
  ctx.beginPath();
  ctx.moveTo(0, 0);
  ctx.arc(0, 0, r, 0.35, Math.PI * 2 - 0.35);
  ctx.closePath();
  ctx.fillStyle = '#2e6e3e';
  ctx.fill();
  ctx.globalAlpha = 0.22;
  ctx.strokeStyle = '#1a4a28';
  ctx.lineWidth = 0.7;
  for (let i = 0; i < 8; i++) {
    const a = (i / 8) * Math.PI * 2;
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.lineTo(Math.cos(a) * r * 0.88, Math.sin(a) * r * 0.88);
    ctx.stroke();
  }
  ctx.globalAlpha = 0.12;
  ctx.fillStyle = '#90ee90';
  ctx.beginPath();
  ctx.ellipse(-r * 0.2, -r * 0.28, r * 0.48, r * 0.22, -0.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
}

const PADS = [
  { rx: 0.07, ry: 0.42, r: 40, rot: 0.5 },
  { rx: 0.91, ry: 0.5, r: 44, rot: -0.8 },
  { rx: 0.5, ry: 0.06, r: 36, rot: 1.3 },
  { rx: 0.18, ry: 0.9, r: 38, rot: 2.2 },
  { rx: 0.78, ry: 0.87, r: 33, rot: -1.5 },
  { rx: 0.35, ry: 0.78, r: 28, rot: 0.9 },
];

const DEFAULT = {
  why: "The Odunlamis build each other up",
  how: ["We choose faith over fear", "We show up fully present", "We speak life over each other"],
  personal: [
    { name: "Dayo", focus: "Lead with courage" },
    { name: "Claire", focus: "Rest & flourish" },
    { name: "Isabella", focus: "Grow in confidence" },
    { name: "Family", focus: "Be kind, be first" },
  ],
};

const panel = (extra = {}) => ({
  position: 'absolute',
  background: 'rgba(8, 45, 38, 0.48)',
  backdropFilter: 'blur(16px)', WebkitBackdropFilter: 'blur(16px)',
  border: '1px solid rgba(255,255,255,0.16)',
  borderRadius: 18, color: '#dff5ef', cursor: 'pointer',
  boxShadow: '0 8px 32px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.08)',
  pointerEvents: 'all',
  ...extra,
});

const LABEL = { fontSize: 8, letterSpacing: '0.22em', color: 'rgba(190,245,230,0.5)', textTransform: 'uppercase', marginBottom: 6 };

export default function KoiBoard() {
  const cvs = useRef(null);
  const st = useRef({ fish: [], ripples: [], cur: { x: -9999, y: -9999 }, tick: 0 });
  const raf = useRef(null);
  const svgImgsRef = useRef([]);
  const useSvgRef = useRef(false);
  const [useSvg, setUseSvg] = useState(false);
  const [board, setBoard] = useState(DEFAULT);
  const [edit, setEdit] = useState(null);
  const [val, setVal] = useState('');

  // Load SVG fish images
  useEffect(() => {
    SVG_URLS.forEach((url, i) => {
      const img = new Image();
      img.onload = () => { svgImgsRef.current[i] = img; };
      img.src = url;
    });
  }, []);

  useEffect(() => {
    const canvas = cvs.current;
    const ctx = canvas.getContext('2d');

    const resize = () => {
      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
      st.current.fish = Array.from({ length: 9 }, () => new Fish(canvas.width, canvas.height));
    };
    resize();
    window.addEventListener('resize', resize);

    const loop = () => {
      const { fish, ripples, cur } = st.current;
      const W = canvas.width, H = canvas.height;
      st.current.tick++;
      const t = st.current.tick * 0.008;

      const bg = ctx.createRadialGradient(W * 0.42, H * 0.35, 0, W * 0.5, H * 0.5, Math.hypot(W, H) * 0.78);
      bg.addColorStop(0, '#42d4be'); bg.addColorStop(0.38, '#1ba898');
      bg.addColorStop(0.72, '#0e7265'); bg.addColorStop(1, '#08504a');
      ctx.fillStyle = bg; ctx.fillRect(0, 0, W, H);

      ctx.save();
      for (let i = 0; i < 22; i++) {
        const cx = (Math.sin(i * 1.618 + t * 0.65) * 0.5 + 0.5) * W;
        const cy = (Math.cos(i * 2.41 + t * 0.48) * 0.5 + 0.5) * H;
        const cr = 28 + Math.sin(i + t * 1.4) * 14;
        const ca = (Math.sin(i * 0.73 + t * 1.9) * 0.5 + 0.5) * 0.075;
        const cg = ctx.createRadialGradient(cx, cy, 0, cx, cy, cr);
        cg.addColorStop(0, `rgba(190,255,235,${ca})`); cg.addColorStop(1, 'transparent');
        ctx.fillStyle = cg; ctx.beginPath(); ctx.arc(cx, cy, cr, 0, Math.PI * 2); ctx.fill();
      }
      for (let i = 0; i < 45; i++) {
        const sx = (Math.sin(i * 3.73 + t * 1.2) * 0.5 + 0.5) * W;
        const sy = (Math.cos(i * 5.17 + t * 0.85) * 0.5 + 0.5) * H;
        const sa = (Math.sin(i + t * 3.1) * 0.5 + 0.5) * 0.48;
        const ss = 1.2 + Math.sin(i * 2.1 + t * 4) * 0.7;
        ctx.globalAlpha = sa; ctx.fillStyle = '#fff';
        ctx.fillRect(sx - ss / 2, sy - ss / 2, ss, ss);
      }
      ctx.globalAlpha = 1; ctx.restore();

      // ── Fish BELOW lily pads ──
      fish.forEach(f => { f.update(W, H, cur); f.draw(ctx, useSvgRef.current ? svgImgsRef.current : null); });

      // ── Ripples ──
      st.current.ripples = ripples.filter(r => !r.isDead());
      st.current.ripples.forEach(r => { r.update(); r.draw(ctx); });

      // ── Lily pads ON TOP ──
      PADS.forEach(p => drawPad(ctx, p.rx * W, p.ry * H, p.r, p.rot));

      raf.current = requestAnimationFrame(loop);
    };
    loop();

    return () => { cancelAnimationFrame(raf.current); window.removeEventListener('resize', resize); };
  }, []);

  const onMove = useCallback(e => {
    const r = cvs.current.getBoundingClientRect();
    st.current.cur = { x: e.clientX - r.left, y: e.clientY - r.top };
  }, []);

  const onTap = useCallback(e => {
    const r = cvs.current.getBoundingClientRect();
    st.current.ripples.push(new Ripple(e.clientX - r.left, e.clientY - r.top));
  }, []);

  const save = () => {
    if (edit === 'why') setBoard(b => ({ ...b, why: val }));
    else if (edit?.startsWith('h-')) { const i = +edit.slice(2); setBoard(b => { const h = [...b.how]; h[i] = val; return { ...b, how: h }; }); }
    else if (edit?.startsWith('p-')) { const i = +edit.slice(2); setBoard(b => { const p = [...b.personal]; p[i] = { ...p[i], focus: val }; return { ...b, personal: p }; }); }
    setEdit(null);
  };

  const open = (key, cur) => { setEdit(key); setVal(cur); };

  return (
    <div style={{ position: 'relative', width: '100%', height: '100vh', overflow: 'hidden', fontFamily: "'Palatino Linotype', Palatino, 'Book Antiqua', Georgia, serif" }}>
      <canvas ref={cvs}
        style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', display: 'block', cursor: 'crosshair' }}
        onMouseMove={onMove} onClick={onTap}
      />

      <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}>
        <div style={panel({ top: '50%', left: '50%', transform: 'translate(-50%,-50%)', width: 192, height: 192, borderRadius: '50%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', padding: 22 })}
          onClick={() => open('why', board.why)}>
          <div style={LABEL}>Why</div>
          <div style={{ fontSize: 13, fontStyle: 'italic', lineHeight: 1.55 }}>{board.why}</div>
          <div style={{ fontSize: 8, color: 'rgba(190,245,230,0.28)', marginTop: 10, letterSpacing: '0.15em' }}>tap to edit</div>
        </div>

        {board.how.map((item, i) => {
          const pos = [{ top: '17%', left: '11%' }, { top: '17%', right: '11%' }, { bottom: '18%', left: '50%', transform: 'translateX(-50%)' }][i];
          return (
            <div key={i} style={panel({ ...pos, padding: '14px 18px', maxWidth: 158 })} onClick={() => open(`h-${i}`, item)}>
              <div style={LABEL}>How</div>
              <div style={{ fontSize: 12.5, lineHeight: 1.55, fontStyle: 'italic' }}>{item}</div>
            </div>
          );
        })}

        {board.personal.map((p, i) => {
          const pos = [{ top: '6%', left: '3%' }, { top: '6%', right: '3%' }, { bottom: '6%', left: '3%' }, { bottom: '6%', right: '3%' }][i];
          return (
            <div key={i} style={panel({ ...pos, padding: '10px 14px', minWidth: 138 })} onClick={() => open(`p-${i}`, p.focus)}>
              <div style={{ fontSize: 12, fontWeight: 'bold', color: 'rgba(190,245,230,0.88)', marginBottom: 4, letterSpacing: '0.05em' }}>{p.name}</div>
              <div style={{ fontSize: 11.5, fontStyle: 'italic', color: 'rgba(223,245,239,0.7)', lineHeight: 1.4 }}>{p.focus}</div>
            </div>
          );
        })}

        <button
          onClick={() => { const next = !useSvg; setUseSvg(next); useSvgRef.current = next; }}
          style={{
            position: 'absolute', bottom: 12, left: 16, pointerEvents: 'all',
            background: useSvg ? 'rgba(255,255,255,0.18)' : 'rgba(255,255,255,0.08)',
            border: '1px solid rgba(255,255,255,0.2)',
            borderRadius: 20, padding: '5px 14px',
            color: 'rgba(255,255,255,0.6)', fontSize: 10,
            cursor: 'pointer', letterSpacing: '0.1em',
            fontFamily: "'Palatino Linotype', Palatino, Georgia, serif",
            transition: 'background 0.2s',
          }}>
          {useSvg ? '🐠 SVG fish' : '✦ canvas fish'}
        </button>
        <div style={{ position: 'absolute', bottom: 12, right: 16, fontSize: 9.5, color: 'rgba(255,255,255,0.3)', letterSpacing: '0.12em' }}>
          hover · click pond · tap panels to edit
        </div>
      </div>

      {edit && (
        <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.52)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 99 }}
          onClick={() => setEdit(null)}>
          <div style={{ background: 'rgba(10, 50, 44, 0.96)', backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)', border: '1px solid rgba(255,255,255,0.14)', borderRadius: 22, padding: 28, minWidth: 310, color: '#dff5ef', fontFamily: "'Palatino Linotype', Palatino, Georgia, serif" }}
            onClick={e => e.stopPropagation()}>
            <div style={{ fontSize: 9, letterSpacing: '0.22em', textTransform: 'uppercase', color: 'rgba(190,245,230,0.45)', marginBottom: 14 }}>
              Edit {edit === 'why' ? 'Why' : edit.startsWith('h-') ? `How ${+edit.slice(2) + 1}` : board.personal[+edit.slice(2)]?.name}
            </div>
            <textarea value={val} onChange={e => setVal(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), save())}
              autoFocus rows={3}
              style={{ width: '100%', padding: '10px 14px', borderRadius: 12, border: '1px solid rgba(255,255,255,0.18)', background: 'rgba(255,255,255,0.07)', color: '#dff5ef', fontSize: 14, fontFamily: "'Palatino Linotype', Palatino, Georgia, serif", fontStyle: 'italic', resize: 'none', outline: 'none', boxSizing: 'border-box' }}
            />
            <div style={{ display: 'flex', gap: 8, marginTop: 14 }}>
              <button onClick={save} style={{ flex: 1, padding: '10px 0', borderRadius: 11, border: 'none', background: 'rgba(62, 185, 155, 0.35)', color: '#dff5ef', fontSize: 13, fontFamily: "'Palatino Linotype', Palatino, Georgia, serif", cursor: 'pointer', letterSpacing: '0.08em' }}>Save</button>
              <button onClick={() => setEdit(null)} style={{ padding: '10px 18px', borderRadius: 11, border: '1px solid rgba(255,255,255,0.18)', background: 'transparent', color: 'rgba(223,245,239,0.6)', fontSize: 13, cursor: 'pointer', fontFamily: "'Palatino Linotype', Palatino, Georgia, serif" }}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
